      map.set(key, [t]);
    }
  }

  const result: DuplicateGroup[] = [];
  for (const [key, txns] of map) {
    if (txns.length > 1) {
      result.push({ key, transactions: txns });
    }
  }
  return result;
}
```

---

### 3. `calculateRunningBalance` Рђћ O(n┬иm┬▓) Рєњ O(n + m log m)

**Problem:** For each of m user-transaction positions: scans all n transactions, re-sorts m items, recalculates cumulative sum from index 0. Total: O(m ├Ќ (n + m log m + m)).

**Fix:** One filter pass (O(n)), sort once (O(m log m)), one map pass for incremental balance (O(m)).

```typescript
export function calculateRunningBalance(
  transactions: Transaction[],
  userId: string
): RunningBalanceEntry[] {
  const userTransactions = transactions.filter(t => t.userId === userId);

  userTransactions.sort((a, b) => a.date.localeCompare(b.date));

  let balance = 0;
  return userTransactions.map(t => {
    balance += t.amount;
    return {
      transactionId: t.id,
      amount: t.amount,
      balance: Math.round(balance * 100) / 100,
      date: t.date,
    };
  });
}
```

---

### 4. `topSpenders` Рђћ O(n┬иk + k┬▓) Рєњ O(n + k log k)

**Problem:** `userIds.includes()` is O(k) per transaction for dedup; then full array re-scan per unique user for totals; then O(k┬▓) bubble sort.

**Fix:** Single pass with `Map<string, {total, count}>` accumulating per-user stats; native `.sort()` for O(k log k) ordering.

```typescript
export function topSpenders(
  transactions: Transaction[],
  n: number
): SpenderSummary[] {
  const map = new Map<string, { total: number; count: number }>();

  for (const t of transactions) {
    const entry = map.get(t.userId);
    if (entry) {
      entry.total += t.amount;
      entry.count++;
    } else {
      map.set(t.userId, { total: t.amount, count: 1 });
    }
  }

  const summaries: SpenderSummary[] = [];
  for (const [userId, { total, count }] of map) {
    summaries.push({
      userId,
      totalSpent: Math.round(total * 100) / 100,
      transactionCount: count,
    });
  }

  summaries.sort((a, b) => b.totalSpent - a.totalSpent);
  return summaries.slice(0, n);
}
```

---

### 5. `searchTransactions` Рђћ O(n┬▓) Рєњ O(n)

**Problem:** New `RegExp` object constructed for every transaction; redundant dedup scan via linear search over `results` (never needed Рђћ each transaction is visited exactly once so it can only be added once).

**Fix:** Compile `RegExp` once before the loop; use `Array.filter()` which has no dedup overhead (no duplicate entries possible since we iterate each transaction exactly once).

```typescript
export function searchTransactions(
  transactions: Transaction[],
  query: string
): Transaction[] {
  const pattern = new RegExp(
    query.replace(/[.*+?^${}()|[\]\\]/g, "\\$&"),
    "i"
  );
  return transactions.filter(t => pattern.test(t.description));
}
```

---

### 6. `processAll` Рђћ no change needed

This function just delegates to the other three. Once those are optimized it will be fast enough.

---

## Complexity Summary

| Function | Before | After |
|---|---|---|
| `groupByCategory` | O(n┬▓) | O(n) |
| `findDuplicates` | O(n┬▓) | O(n) |
| `calculateRunningBalance` | O(n┬иm┬▓) | O(n + m log m) |
| `topSpenders` | O(n┬иk + k┬▓) | O(n + k log k) |
| `searchTransactions` | O(n┬▓) | O(n) |

---

## Correctness Preservation Notes

- `groupByCategory`: Output order changes (Map insertion order vs array.find order) Рђћ but both produce same insertion order since we encounter categories in transaction order. No correctness issue.
- `findDuplicates`: The new approach produces identical groups Рђћ same keys, same transactions per group. Order within `transactions` array of each group is preserved (insertion order).
- `calculateRunningBalance`: Identical output Рђћ same filter, same sort, same incremental balance (rounding is identical: `Math.round(balance * 100) / 100`).
- `topSpenders`: Identical output Рђћ same totals, same counts, same sort order.
- `searchTransactions`: Identical output Рђћ same regex escape, same case-insensitive flag, same matching logic, same result order.

---

## Verification

```bash
# Run correctness tests
npx vitest run tests/pipeline.test.ts

# Run performance tests
npx vitest run tests/performance.test.ts

# Run all tests
npm test
```

All 6 describe blocks in `pipeline.test.ts` and all 6 describe blocks in `performance.test.ts` should pass (green).

